#include<bits/stdc++.h>
using namespace std;
pair<int,int>p[100005];
bool cmp(pair<int,int>x,pair<int,int>y){
	return x.first-x.second>y.first-y.second;
}
int main()
{
	int n;
	cin>>n;
	int ans=0,maxi=0,cnt=0;
	for(int i=1;i<=n;i++){
		cin>>p[i].first>>p[i].second;
	}
	sort(p+1,p+n+1,cmp);
	for(int i=1;i<=n;i++){
		if(ans<p[i].first){
			cnt=cnt+(p[i].first-ans);
			ans+=(p[i].first-ans);
		//	cout<<ans<<endl;
		}
		ans-=p[i].second;
	//	cout<<ans<<endl;
	}
	cout<<cnt;
}
